class Tracker:
    def __init__(self, log):
        self.log = log

    def __enter__(self):
        # Setup: record entry, then hand the manager itself to the `as` name.
        self.log.append("enter")
        return self

    def __exit__(self, exc_type, exc_value, traceback):
        # Teardown: runs on every way out of the block.
        self.log.append("exit")

