exercises.solution_code:
class Transaction:
    def __init__(self, db):
        self.db = db

    def __enter__(self):
        self.db.append("begin")
        return self.db

    def __exit__(self, exc_type, exc_value, traceback):
        # Branch only on commit-vs-rollback; the "close" cleanup is
        # unconditional so it runs on success and on failure alike.
        if exc_type is None:
            self.db.append("commit")
        else:
            self.db.append("rollback")
        self.db.append("close")
        # Return a falsy value (implicitly None) so any exception propagates.

class suppress_type:
    def __init__(self, exc_class):
        self.exc_class = exc_class

    def __enter__(self):
        return self

    def __exit__(self, exc_type, exc_value, traceback):
        # Only a real exception of the right type is suppressed. A clean exit
        # has exc_type is None and must NOT be "suppressed".
        return exc_type is not None and issubclass(exc_type, self.exc_class)

class temp_table:
    def __init__(self, store, name):
        self.store = store
        self.name = name

    def __enter__(self):
        # Setup: create the temporary table and hand its row list to the test.
        self.store[self.name] = []
        return self.store[self.name]

    def __exit__(self, exc_type, exc_value, traceback):
        # Teardown: drop the table unconditionally so cleanup is deterministic
        # whether the test passed or failed. Returning None (falsy) means we
        # never suppress the test's exception.
        del self.store[self.name]
